//! This module provides the SINGLE SOURCE OF TRUTH for gas accounting of system transactions.
//! System transactions use unlimited EVM gas (u64::MAX) for execution, but contribute differently
//! to block gas limits:
//! - AsyncCommitment (0x11): Contribute ZERO gas to block gas limit
//! - AsyncSettlement (0x12): Contribute calldata-based gas to block gas limit
//! - Scheduled (0x10): Contribute calldata-based gas to block gas limit
//!
//! Note: System transactions may consume different amounts of gas during execution than what
//! they contribute to the block gas limit. This is intentional and allows for unbounded
//! execution while maintaining fair block gas accounting.

/// Transaction type constants (must match alloy_eips::eip2718)
pub const TX_TYPE_SCHEDULED: u8 = 0x10;
pub const TX_TYPE_ASYNC_COMMITMENT: u8 = 0x11;
pub const TX_TYPE_ASYNC_SETTLEMENT: u8 = 0x12;

/// Gas cost constants (EIP-2028)
const TX_BASE_COST: u64 = 21_000;
const ZERO_BYTE_COST: u64 = 4;
const NON_ZERO_BYTE_COST: u64 = 16;
